    let raw = path.trim();
    let cwd = std::env::current_dir().unwrap_or_default();

    let dir = if raw == "." {
        cwd.clone()
    } else {
        let p = pathbuf::from(raw);
        if p.is_absolute() {
            p
        } else {
            cwd.join(&p)
        }
    };

