                if let ok(canon_parent) = parent.canonicalize() {
                    if let some(name) = dir.file_name() {
                        let safe = canon_parent.join(name);
                        if safe
                            .canonicalize()
                            .map(|c| c.starts_with(&canon_parent))
                            .unwrap_or(true)
                        {
                            safe
                        } else {
                            eprintln!(
                                "  {} path traversal blocked",
                                ui::theme::paint_error_label(&t, "\u{2717}")
