        types.push("rust");
    }
    if has_file("go.mod") {
        types.push("go");
    }
    if has_file("pyproject.toml") || has_file("setup.py") || has_file("requirements.txt") {
        types.push("python");
    }
    if has_file("package.json") {
        types.push("javascript");
    }
    if has_file("index.html") && has_file("style.css") {
        types.push("html_css");
    }
    if has_file("dart.yaml") || has_file("pubspec.yaml") {
        types.push("dart");
    }
